import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * REBATE - a multi-field fixed-width batch program, translated from COBOL
 * 85. Defect variant: a field-offset error, the canonical fixed-width
 * copybook bug. This translation miscounts R-ID as three bytes wide, so it
 * decodes R-AMOUNT starting one byte early (offset 3 instead of 4) - the
 * misread slice is still seven digits (the last digit of R-ID plus the
 * first six of the amount), so it parses cleanly to a wrong value on every
 * record. Empty input still agrees; any record diverges.
 */
public final class Rebate {

    private static final BigDecimal ONE = new BigDecimal("1");
    private static final BigDecimal THRESHOLD = new BigDecimal("100.00");
    private static final BigDecimal RATE = new BigDecimal("0.02");
    private static final BigDecimal PIC_9_4_V99 = new BigDecimal("10000");
    private static final BigDecimal PIC_9_6_V99 = new BigDecimal("1000000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        BigDecimal rebate = BigDecimal.ZERO;
        BigDecimal qual = BigDecimal.ZERO;
        BigDecimal recs = BigDecimal.ZERO;

        String line;
        while ((line = in.readLine()) != null) {
            BigDecimal amount = amountOf(line);
            recs = recs.add(ONE);
            if (amount.compareTo(THRESHOLD) >= 0) {
                BigDecimal one = amount.multiply(RATE).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_4_V99);
                rebate = rebate.add(one).remainder(PIC_9_6_V99);
                qual = qual.add(ONE);
            }
        }

        StringBuilder out = new StringBuilder();
        out.append("REBATE=").append(rebate.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("QUAL=").append(qual.toPlainString()).append('\n');
        out.append("RECS=").append(recs.toPlainString()).append('\n');
        System.out.print(out);
    }

    private static BigDecimal amountOf(String rec) {
        return new BigDecimal(rec.substring(3, 10)).movePointLeft(2); // BUG: R-AMOUNT starts at byte 4, not 3
    }
}
